fn on_load(env: rustler::Env, _info: rustler::Term) -> bool {
    env.register::<VisitorHandle>()
        .expect("Failed to register resource type VisitorHandle");
    true
}

rustler::init!("Elixir.HtmlToMarkdown.Native", load = on_load);
